    inherit = jmvcore::Analysis,
    public = list(
        initialize = function(options, data=NULL, datasetId="", analysisId="", revision=0) {
            super$initialize(
                package = "ClinicoPath",
                name = "groomecompare",
                version = c(0,0,34),
                options = options,
                results = groomecompareResults$new(options=options),
                data = data,
                datasetId = datasetId,
                analysisId = analysisId,
                revision = revision,
                pause = NULL,
                completeWhenFilled = FALSE,
                requiresMissings = FALSE,
                weightsSupport = 'auto')
        }))

#' Groome Staging System Comparison
#'
#' Compare two staging systems using Groome criteria (Groome et al., 2001). 
#' Calculates four key metrics: hazard consistency, hazard discrimination, 
#' sample balance, and outcome prediction. Provides overall rank to determine 
#' which staging system performs better. Includes C-index comparison, radar 
#' charts, and side-by-side Kaplan-Meier curves.
#'
#' @examples
#' # Example: Compare ypTNM vs RPA staging systems
#' # Generate sample survival data with two staging systems
#' set.seed(12345)
#' n <- 150
#'
#' survData <- data.frame(
#'     time = rexp(n, 0.05),
#'     event = rbinom(n, 1, 0.6),
#'     ypTNM = factor(sample(c("Stage I", "Stage II", "Stage III", "Stage IV"),
#'                          n, replace = TRUE, prob = c(0.3, 0.3, 0.25, 0.15))),
#'     RPA = factor(sample(c("Low Risk", "Intermediate", "High Risk"),
#'                        n, replace = TRUE, prob = c(0.4, 0.35, 0.25)))
#' )
#'
#' # Compare staging systems using Groome criteria
#' groomecompare(
#'     data = survData,
#'     time = "time",
#'     event = "event",
#'     stage1 = "ypTNM",
#'     stage2 = "RPA",
#'     stage1name = "ypTNM Staging",
#'     stage2name = "RPA Classification",
#'     eventValue = "1",
#'     radarplot = TRUE,
#'     kmplots = TRUE,
#'     detailedmetrics = TRUE,
#'     cindexcompare = TRUE,
#'     bootstrap = FALSE
#' )
#'
#' # With bootstrap validation (smaller nboot for speed)
#' groomecompare(
#'     data = survData,
#'     time = "time",
#'     event = "event",
#'     stage1 = "ypTNM",
#'     stage2 = "RPA",
#'     stage1name = "ypTNM Staging",
#'     stage2name = "RPA Classification",
#'     bootstrap = TRUE,
#'     nboot = 100,
#'     seed = 12345
#' )
#'
#' @param data .
#' @param time a (non-negative valued) vector of survival times
#' @param event the status indicator (0=censored, 1=event)
#' @param stage1 first staging system to compare (e.g., ypTNM stage)
#' @param stage2 second staging system to compare (e.g., RPA stage)
#' @param eventValue the value representing an event
#' @param stage1name descriptive name for first staging system
#' @param stage2name descriptive name for second staging system
#' @param radarplot .
#' @param barplot .
#' @param kmplots .
#' @param detailedmetrics .
#' @param hazardratios .
#' @param samplesize .
#' @param cindexcompare .
#' @param bootstrap .
#' @param nboot .
#' @param seed .
#' @return A results object containing:
#' \tabular{llllll}{
#'   \code{results$instructions} \tab \tab \tab \tab \tab a html \cr
#'   \code{results$summary} \tab \tab \tab \tab \tab a table \cr
#'   \code{results$detailedmetrics$consistency} \tab \tab \tab \tab \tab a table \cr
#'   \code{results$detailedmetrics$discrimination} \tab \tab \tab \tab \tab a table \cr
#'   \code{results$hazardratios$hrs1} \tab \tab \tab \tab \tab a table \cr
#'   \code{results$hazardratios$hrs2} \tab \tab \tab \tab \tab a table \cr
#'   \code{results$samplesize} \tab \tab \tab \tab \tab a table \cr
#'   \code{results$cindexcompare} \tab \tab \tab \tab \tab a table \cr
#'   \code{results$radarplot} \tab \tab \tab \tab \tab an image \cr
#'   \code{results$barplot} \tab \tab \tab \tab \tab an image \cr
#'   \code{results$kmplot1} \tab \tab \tab \tab \tab an image \cr
#'   \code{results$kmplot2} \tab \tab \tab \tab \tab an image \cr
#'   \code{results$bootstrap} \tab \tab \tab \tab \tab a table \cr
#'   \code{results$notices} \tab \tab \tab \tab \tab a html \cr
#' }
#'
#' Tables can be converted to data frames with \code{asDF} or \code{\link{as.data.frame}}. For example:
#'
#' \code{results$summary$asDF}
#'
#' \code{as.data.frame(results$summary)}
#'
#' @export
groomecompare <- function(
    data,
    time,
    event,
    stage1,
    stage2,
    eventValue = "1",
    stage1name = "Staging System 1",
    stage2name = "Staging System 2",
    radarplot = TRUE,
    barplot = FALSE,
    kmplots = TRUE,
    detailedmetrics = TRUE,
    hazardratios = TRUE,
    samplesize = TRUE,
    cindexcompare = TRUE,
    bootstrap = FALSE,
    nboot = 1000,
    seed = 12345) {

    if ( ! requireNamespace("jmvcore", quietly=TRUE))
        stop("groomecompare requires jmvcore to be installed (restart may be required)")

    if ( ! missing(time)) time <- jmvcore::resolveQuo(jmvcore::enquo(time))
    if ( ! missing(event)) event <- jmvcore::resolveQuo(jmvcore::enquo(event))
    if ( ! missing(stage1)) stage1 <- jmvcore::resolveQuo(jmvcore::enquo(stage1))
    if ( ! missing(stage2)) stage2 <- jmvcore::resolveQuo(jmvcore::enquo(stage2))
    if (missing(data))
        data <- jmvcore::marshalData(
            parent.frame(),
            `if`( ! missing(time), time, NULL),
            `if`( ! missing(event), event, NULL),
            `if`( ! missing(stage1), stage1, NULL),
            `if`( ! missing(stage2), stage2, NULL))

    for (v in event) if (v %in% names(data)) data[[v]] <- as.factor(data[[v]])
    for (v in stage1) if (v %in% names(data)) data[[v]] <- as.factor(data[[v]])
    for (v in stage2) if (v %in% names(data)) data[[v]] <- as.factor(data[[v]])

    options <- groomecompareOptions$new(
        time = time,
        event = event,
        stage1 = stage1,
        stage2 = stage2,
        eventValue = eventValue,
        stage1name = stage1name,
        stage2name = stage2name,
        radarplot = radarplot,
        barplot = barplot,
        kmplots = kmplots,
        detailedmetrics = detailedmetrics,
        hazardratios = hazardratios,
        samplesize = samplesize,
        cindexcompare = cindexcompare,
        bootstrap = bootstrap,
        nboot = nboot,
        seed = seed)

    analysis <- groomecompareClass$new(
        options = options,
        data = data)

    analysis$run()

    analysis$results
}

